(()=>{(function(){const t=document.getElementById("swagger-ui");!t||typeof window.SwaggerUIBundle!="function"||window.SwaggerUIBundle({url:t.dataset.specUrl||"/api/docs/openapi.yaml",dom_id:"#swagger-ui",presets:[window.SwaggerUIBundle.presets.apis,window.SwaggerUIBundle.SwaggerUIStandalonePreset],layout:"BaseLayout",deepLinking:!0,tryItOutEnabled:!0,requestInterceptor:e=>e.method!=="GET"&&!e.headers["X-CSRF-Token"]?fetch("/api/csrf-token").then(n=>n.json()).then(n=>(e.headers["X-CSRF-Token"]=n.csrfToken,e)):e})})();})();
